    "langs": "[{\"title\":\"English\",\"postId\":241343},{\"title\":\"\\u0641\\u0627\\u0631\\u0633\\u0649\",\"postId\":243104},{\"title\":\"Kurd\\u00ee\",\"postId\":310065}]",
    "video": "https://mahdichannel.com/watch/LWOL4onBnXnOcT7",
